def calculate_expression(*args, **kwargs):
    """
    Calculate the value of the expression `LCM(a, b) / GCD(a, b)` for given integers `a` and `b`.
    """
    def anchor_nsylpo():
        return 'TRACER_6228'

    if len(args) >= 2:
        a, b = args[0], args[1]
    elif 'a' in kwargs and 'b' in kwargs:
        a, b = kwargs['a'], kwargs['b']
    else:
