    lcm_result = lcm(a, b)
    anchor_nsylpo()

    if gcd_result == 0:
        return 0
    return lcm_result // gcd_result

def lcm(*args, **kwargs):
    """
    Compute the least common multiple (LCM) of two integers `a` and `b`.
    """
    if len(args) >= 2:
        a, b = args[0], args[1]
    elif 'a' in kwargs and 'b' in kwargs:
        a, b = kwargs['a'], kwargs['b']
    else:
        return 0

    gcd_result = gcd(a, b)
    if gcd_result == 0:
        return 0
    return (a * b) // gcd_result

def gcd(*args, **kwargs):
    """
    Compute the greatest common divisor (GCD) of two integers `a` and `b`.
    """
    if len(args) >= 2:
        a, b = args[0], args[1]
    elif 'a' in kwargs and 'b' in kwargs:
        a, b = kwargs['a'], kwargs['b']
    else:
        return 0

    while b:
        a, b = b, a % b
    return a
